<grid type="Report" xmlns="urn:schemas-fast-com:data-grid">
  <title v="Tạo số liệu kiểm kê" e="Generate Stocktaking Data"></title>
  <subTitle v="Phiếu kiểm kê số: %s..." e="Stocktaking No.: %s..."></subTitle>
  <fields>
    <field name="tag" type="Boolean" width="60" filterSource="Tag">
      <header v="&lt;div onclick=&quot;toggle$Grid(this);&quot; style=&quot;cursor:pointer;background-position:3px 3px;&quot; class=&quot;HeaderArrowImage&quot;&gt;Chọn&lt;/div&gt;" e="&lt;div onclick=&quot;toggle$Grid(this);&quot; style=&quot;cursor:pointer;background-position:3px 3px;&quot; class=&quot;HeaderArrowImage&quot;&gt;Select&lt;/div&gt;"></header>
      <clientScript><![CDATA[<Encrypted>&96EB7KSJ4WpQv9tz7CWyJbtHo3Q0hC+ZW+BSt29RDWP80Vcedfyf9uv/1yggap7nO4MFdA1VF5YBLaFiF/rXPQ==</Encrypted>]]></clientScript>
    </field>

    <field name="ma_kho" width="100" allowSorting="true" allowFilter="true" readOnly="true">
      <header v="Mã kho" e="Site"></header>
    </field>
    <field name="ma_vi_tri" width="100" allowSorting="true" allowFilter="true" readOnly="true">
      <header v="Mã vị trí" e="Location"></header>
    </field>

    <field name="ma_vt" width="100" allowSorting="true" allowFilter="true" readOnly="true">
      <header v="Mã vật tư" e="Item"></header>
    </field>
    <field name="ten_vt" width="300" allowSorting="true" allowFilter="true" readOnly="true">
      <header v="Tên vật tư" e="Description"></header>
    </field>
    <field name="dvt" width="50" allowSorting="true" allowFilter="true" readOnly="true">
      <header v="Đvt" e="UOM"></header>
    </field>
    <field name="ma_lo" width="100" allowSorting="true" allowFilter="true" readOnly="true">
      <header v="Mã lô" e="Lot"></header>
    </field>
    <field name="ton_hd" type="Decimal" dataFormatString="@quantityViewFormat" width="100" allowSorting="true" aggregate="Sum" readOnly="true" allowFilter="&GridListAllowFilter.Number;">
      <header v="Số lượng" e="Quantity"></header>
    </field>

    <field name="xKey" readOnly="true" hidden="true">
      <header v="" e=""></header>
    </field>
  </fields>

  <views>
    <view id="Grid">
      <field name="tag"/>

      <field name="ma_kho"/>
      <field name="ma_vi_tri"/>

      <field name="ma_vt"/>
      <field name="ten_vt"/>
      <field name="dvt"/>
      <field name="ma_lo"/>
      <field name="ton_hd"/>

      <field name="xKey"/>
    </view>
  </views>

